1265       if (Predicate == ICmpInst::ICMP_ULT || Predicate == ICmpInst::ICMP_ULE)
1266         Result = 1;
1267       break;
1268     case ICmpInst::ICMP_SLE:
1269       if (Predicate == ICmpInst::ICMP_SGT)
